// The postcondition of det_kill_scheduled_thread is the implication
//
//   ({ &&& post1_self_.wf() &&& ... &&& post2_self_.wf() &&& ... }) ==>
//       det_kill_scheduled_thread_equal(r1, r2, post1_self_, post2_self_)
//
// The previous attempt asserted `post1_self_.wf()` (and friends) at the
// top level of the proof body.  Those assertions are not derivable from
// the function's preconditions — they live on the *left-hand side* of
// the implication in `ensures`, so Verus only gets them as hypotheses
// once we explicitly introduce them.  Hence the assertion failures on
// lines 3181-3189.
//
// To repair this, we wrap every assertion that mentions `post1_self_` /
// `post2_self_` inside an `if`-block whose condition is exactly the
// antecedent of the implication.  Inside that block, all the ensures
// conjuncts are known and the per-run / cross-run trigger lemmas we
// want z3 to instantiate become provable.

let owning_proc = pre_self_.get_thread(thread_ptr).owning_proc;

if post1_self_.wf()
    && post2_self_.wf()
    && (post1_self_.thread_dom() == pre_self_.thread_dom().remove(thread_ptr))
    && (post2_self_.thread_dom() == pre_self_.thread_dom().remove(thread_ptr))
    && threads_unchanged_except(pre_self_, post1_self_, set![])
    && threads_unchanged_except(pre_self_, post2_self_, set![])
    && (post1_self_.proc_dom() == pre_self_.proc_dom())
    && (post2_self_.proc_dom() == pre_self_.proc_dom())
    && process_tree_unchanged(pre_self_, post1_self_)
    && process_tree_unchanged(pre_self_, post2_self_)
    && (post1_self_.container_dom() == pre_self_.container_dom())
    && (post2_self_.container_dom() == pre_self_.container_dom())
    && containers_tree_unchanged(pre_self_, post1_self_)
    && containers_tree_unchanged(pre_self_, post2_self_)
    && process_mem_unchanged(pre_self_, post1_self_)
    && process_mem_unchanged(pre_self_, post2_self_)
    && (post1_self_.page_closure() =~= pre_self_.page_closure().remove(r1.0))
    && (post2_self_.page_closure() =~= pre_self_.page_closure().remove(r2.0))
    && pre_self_.page_closure().contains(r1.0)
    && pre_self_.page_closure().contains(r2.0)
    && (r1.0 == r1.1@.addr())
    && (r2.0 == r2.1@.addr())
    && r1.1@.is_init()
    && r2.1@.is_init()
    && (pre_self_.container_dom().contains(r1.0) == false)
    && (pre_self_.container_dom().contains(r2.0) == false)
{
    // Cross-run domain extensionality: both post states agree on the
    // sub-domains the ensures pin down purely in terms of pre_self_.
    assert(post1_self_.thread_dom() =~= post2_self_.thread_dom());
    assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());
    assert(post1_self_.container_dom() =~= post2_self_.container_dom());

    // Re-state both page_closure equations so the `=~=` trigger fires
    // on both r1 / r2 sides simultaneously.
    assert(post1_self_.page_closure() =~= pre_self_.page_closure().remove(r1.0));
    assert(post2_self_.page_closure() =~= pre_self_.page_closure().remove(r2.0));

    // Anchor: both `r{1,2}.0` are inside `pre_self_.page_closure()` and
    // not inside `pre_self_.container_dom()`, so they live in
    // `proc_dom ∪ thread_dom ∪ endpoint_dom`.
    assert(pre_self_.page_closure().contains(r1.0));
    assert(pre_self_.page_closure().contains(r2.0));
    assert(pre_self_.container_dom().contains(r1.0) == false);
    assert(pre_self_.container_dom().contains(r2.0) == false);

    // Tuple/permission view anchoring.
    assert(r1.0 == r1.1@.addr());
    assert(r2.0 == r2.1@.addr());
    assert(r1.1@.is_init());
    assert(r2.1@.is_init());

    // owned_threads@ are equal across the two runs (both equal to
    // pre.get_proc(owning_proc).owned_threads@.remove_value(thread_ptr)).
    assert(post1_self_.get_proc(owning_proc).owned_threads@
        == pre_self_.get_proc(owning_proc).owned_threads@.remove_value(thread_ptr));
    assert(post2_self_.get_proc(owning_proc).owned_threads@
        == pre_self_.get_proc(owning_proc).owned_threads@.remove_value(thread_ptr));
    assert(post1_self_.get_proc(owning_proc).owned_threads@
        =~= post2_self_.get_proc(owning_proc).owned_threads@);
}
